// // This module implements a 16-bit shift register with parallel load capability.
// On the reset signal, initialize the register to 0.
// On each positive edge of the clock signal, if the load signal is low, load the input value into the register. Otherwise, shift the contents of the register to the left.
module shift_register_16bit(
    input wire clk,
    input wire rst,
    input wire load,
    input wire [15:0] data_in,
    output reg [15:0] data_out
);

    always @(posedge clk) begin
        if (rst) begin
            data_out <= 16'b0000000000000000;
        end else if (load) begin
            data_out <= data_in;
        end else begin
            data_out <= data_out >> 1;
        end
    end
endmodule

